function getBookingMissingItems(form, selectedSession, selectedSlots) { const items = []; if (!selectedSlots.length) items.push("Select at least one available lesson time block"); if (!form.childOneName.trim()) items.push("Child 1 full name"); if (!form.childOneAge.trim()) items.push("Child 1 age"); if (selectedSession.id === "duo" && !form.childTwoName.trim()) items.push("Child 2 full name"); if (selectedSession.id === "duo" && !form.childTwoAge.trim()) items.push("Child 2 age"); if (!form.parentName.trim()) items.push("Primary parent/guardian name"); if (!form.email.trim()) items.push("Parent email"); if (!form.phone.trim()) items.push("Parent phone"); if (!hasEmergencyContact(form, selectedSession.id)) items.push("Emergency contact info"); if (!form.signature.trim()) items.push("Draw the parent/guardian signature"); if (!form.agreesWaiver) items.push("Agree to the riding waiver"); if (!form.agreesHelmet) items.push("Agree to helmet and safety rules"); if (!form.agreesPolicy) items.push("Agree to cancellation, late arrival, weather, and no-show policies"); return items; }
