function InstructorPage(props) { const { siteContent, updateContent, activeWeekStart, setActiveWeekStart, weekOptions, instructorDay, setInstructorDay, instructorDaySlots, availability, bookings, openSlots, filteredBookings, bookingSearch, setBookingSearch, stats, setDayNotWorking, toggleInstructorSlot, removeAvailability, cancelBooking, deleteBooking, markPaid, campSignups, supabaseMessage, isLoadingData, isSavingData, supabase, instructorSignedIn, instructorAccessChecked, instructorAccessApproved, authEmail, setAuthEmail, authPassword, setAuthPassword, signInInstructor, createInstructorAuthAccount, signOutInstructor, devMode, startDevMode, setDevMode, editProps } = props; const instructorCanEdit = Boolean(instructorSignedIn && instructorAccessApproved); if (!instructorCanEdit) return <InstructorLoginGate message={supabaseMessage} isLoading={isLoadingData} isSaving={isSavingData} isConnected={Boolean(supabase)} instructorSignedIn={instructorSignedIn} instructorAccessChecked={instructorAccessChecked} instructorAccessApproved={instructorAccessApproved} authEmail={authEmail} setAuthEmail={setAuthEmail} authPassword={authPassword} setAuthPassword={setAuthPassword} onSignIn={signInInstructor} onCreateAccount={createInstructorAuthAccount} onSignOut={signOutInstructor} />; return <div className="grid gap-6 lg:grid-cols-[0.9fr_1.1fr]"><Card className="rounded-3xl"><CardContent className="p-7"><div className="flex items-center gap-3"><Settings className="h-6 w-6" /><EditableText value={siteContent.instructorScheduleTitle} onChange={(value) => updateContent("instructorScheduleTitle", value)} as="h3" className="text-2xl font-semibold" {...editProps} /></div><EditableText value={siteContent.instructorScheduleText} onChange={(value) => updateContent("instructorScheduleText", value)} as="p" multiline className="mt-2 text-stone-600" {...editProps} /><div className="mt-6 grid gap-5"><WeekSelector weekOptions={weekOptions} value={activeWeekStart} onChange={setActiveWeekStart} /><div className="flex flex-wrap gap-2">{DAYS.map((day) => { const selectedCount = getDaySelectedSlots(availability, activeWeekStart, day).length; const bookedCount = bookings.filter((booking) => booking.weekStart === activeWeekStart && booking.day === day && booking.status !== "Canceled").length; return <Button key={day} type="button" variant={instructorDay === day ? "default" : "outline"} onClick={() => setInstructorDay(day)} className="rounded-full">{day.slice(0, 3)} {selectedCount > 0 && <span className="ml-1 text-xs">({selectedCount})</span>} {bookedCount > 0 && <span className="ml-1 text-xs">• {bookedCount} booked</span>}</Button>; })}</div><div className="rounded-3xl border bg-white p-5"><div className="flex flex-col gap-4 md:flex-row md:items-center md:justify-between"><div><p className="text-sm font-semibold uppercase tracking-wide text-stone-500">{formatFullDate(getDateForDay(activeWeekStart, instructorDay))}</p><EditableText value={siteContent.selectBlocksTitle} onChange={(value) => updateContent("selectBlocksTitle", value)} as="h4" className="mt-1 text-2xl font-semibold" {...editProps} /><EditableText value={siteContent.selectBlocksText} onChange={(value) => updateContent("selectBlocksText", value)} as="p" multiline className="mt-1 text-sm text-stone-600" {...editProps} /></div><Button type="button" variant="outline" onClick={setDayNotWorking} className="rounded-full"><EditableText value={siteContent.notWorkingButton} onChange={(value) => updateContent("notWorkingButton", value)} as="span" {...editProps} /></Button></div><div className="mt-6 grid gap-3 sm:grid-cols-2">{instructorDaySlots.map((slot) => <button key={slot.time} type="button" disabled={slot.filled} onClick={() => toggleInstructorSlot(slot.time)} className={classNames("rounded-2xl border p-4 text-left transition", slot.filled && "cursor-not-allowed border-amber-200 bg-amber-50 text-amber-900", !slot.filled && slot.selected && "border-stone-950 bg-stone-950 text-white", !slot.filled && !slot.selected && "border-stone-200 bg-stone-50 hover:border-stone-950")}><div className="flex items-center justify-between gap-3"><div><p className="font-semibold">{slot.time} – {slot.end}</p><p className={classNames("mt-1 text-sm", slot.selected && !slot.filled ? "text-stone-200" : "text-stone-600")}>{slot.filled ? `Filled by ${slot.booking?.sessionName || "booking"}` : slot.selected ? "Available to customers" : "Not working"}</p></div><Badge label={slot.filled ? "Filled" : slot.selected ? "Open" : "Off"} tone={slot.filled ? "amber" : slot.selected ? "green" : "gray"} /></div></button>)}</div></div></div></CardContent></Card><div className="grid gap-6"><FullSiteEditorCard siteContent={siteContent} updateContent={updateContent} devMode={devMode && instructorCanEdit} disabled={!instructorCanEdit} startDevMode={startDevMode} stopDevMode={() => setDevMode(false)} /><div className="grid gap-4 md:grid-cols-5"><StatCard label="Open blocks" value={stats.openCount} /><StatCard label="Filled blocks" value={stats.filledCount} /><StatCard label="Private" value={stats.privateCount} /><StatCard label="Duo" value={stats.duoCount} /><StatCard label="Projected" value={currency(stats.projectedRevenue)} /></div><Card className="rounded-3xl"><CardContent className="p-7"><div className="flex items-center justify-between gap-4"><EditableText value={siteContent.calendarBlocksTitle} onChange={(value) => updateContent("calendarBlocksTitle", value)} as="h3" className="text-2xl font-semibold" {...editProps} /><Badge label={`${openSlots.length} total`} tone="gray" /></div><div className="mt-5 grid gap-3">{openSlots.map((slot) => <div key={slot.id} className="flex flex-col gap-3 rounded-2xl border bg-white p-4 md:flex-row md:items-center md:justify-between"><div><p className="font-semibold">{formatFullDate(slot.date)} at {getBlockLabel(slot.time)}</p><p className="text-sm text-stone-600">75-minute block · {slot.available ? "Open" : `Filled by ${slot.booking?.sessionName || "booking"}`}</p></div><div className="flex items-center gap-2"><Badge label={slot.available ? "Open" : "Filled"} tone={slot.available ? "green" : "amber"} />{slot.available && <Button type="button" variant="outline" size="sm" onClick={() => removeAvailability(slot.blockId)} className="rounded-full"><Trash2 className="h-4 w-4" /></Button>}</div></div>)}{!openSlots.length && <p className="rounded-2xl border bg-white p-4 text-sm text-stone-600">No availability blocks for this week yet.</p>}</div></CardContent></Card><Card className="rounded-3xl"><CardContent className="p-7"><div className="flex flex-col gap-4 md:flex-row md:items-center md:justify-between"><EditableText value={siteContent.bookingsTitle} onChange={(value) => updateContent("bookingsTitle", value)} as="h3" className="text-2xl font-semibold" {...editProps} /><input value={bookingSearch} onChange={(event) => setBookingSearch(event.target.value)} placeholder={siteContent.bookingSearchPlaceholder} className="rounded-2xl border border-stone-200 bg-white px-4 py-3 text-sm outline-none focus:border-stone-950 md:w-80" /></div><div className="mt-5 grid gap-4">{filteredBookings.map((booking) => <BookingCard key={booking.id} booking={booking} onCancel={cancelBooking} onDelete={deleteBooking} onMarkPaid={markPaid} />)}{!filteredBookings.length && <p className="rounded-2xl border bg-white p-4 text-sm text-stone-600">No bookings match this view.</p>}</div></CardContent></Card><Card className="rounded-3xl"><CardContent className="p-7"><h3 className="text-2xl font-semibold">Camp signups</h3><div className="mt-5 grid gap-4">{campSignups.map((signup) => <div key={signup.id} className="rounded-3xl border bg-white p-5"><div className="flex flex-wrap items-center gap-2"><h4 className="text-lg font-semibold">{Array.isArray(signup.children) && signup.children.length ? signup.children.map((child) => child.name).join(", ") : signup.childName}</h4><Badge label={signup.status} tone="blue" /></div><div className="mt-4 grid gap-2 text-sm text-stone-700 md:grid-cols-2"><p><span className="font-semibold">Children:</span> {Array.isArray(signup.children) && signup.children.length ? signup.children.map((child) => `${child.name} (${child.age})`).join(", ") : `${signup.childName} (${signup.childAge})`}</p><p><span className="font-semibold">Experience:</span> {signup.experience || "Not specified"}</p><p><span className="font-semibold">Parent:</span> {signup.parentName}</p><p><span className="font-semibold">Phone:</span> {signup.phone}</p><p><span className="font-semibold">Email:</span> {signup.email}</p><p><span className="font-semibold">Emergency:</span> {signup.emergencyContact} · {signup.emergencyPhone}</p></div>{signup.preferredDates && <p className="mt-3 text-sm text-stone-700"><span className="font-semibold">Preferred dates:</span> {signup.preferredDates}</p>}{signup.medicalNotes && <p className="mt-2 text-sm text-stone-700"><span className="font-semibold">Medical:</span> {signup.medicalNotes}</p>}{signup.notes && <p className="mt-2 text-sm text-stone-700"><span className="font-semibold">Notes:</span> {signup.notes}</p>}</div>)}{!campSignups.length && <p className="rounded-2xl border bg-white p-4 text-sm text-stone-600">No camp signups yet.</p>}</div></CardContent></Card></div></div>; }
function InstructorLoginGate({ message, isLoading, isSaving, isConnected, instructorSignedIn, instructorAccessChecked, instructorAccessApproved, authEmail, setAuthEmail, authPassword, setAuthPassword, onSignIn, onCreateAccount, onSignOut }) { return <div className="flex min-h-[65vh] items-center justify-center px-4"><Card className="w-full max-w-xl rounded-3xl border-stone-200 bg-white shadow-xl"><CardContent className="p-8 md:p-10"><div className="mx-auto flex h-16 w-16 items-center justify-center rounded-3xl bg-stone-950 text-white"><ShieldCheck className="h-8 w-8" /></div><div className="mt-5 text-center"><h2 className="text-3xl font-bold tracking-tight">Instructor sign in</h2><p className="mt-3 text-sm leading-6 text-stone-600">Sign in to load the instructor portal, schedule controls, booking dashboard, payment tracking, and website editor.</p></div><div className="mt-7 grid gap-4"><Input label="Instructor email" type="email" value={authEmail} onChange={setAuthEmail} autoComplete="off" name="moonstone-instructor-email" /><Input label="Instructor password" type="password" value={authPassword} onChange={setAuthPassword} autoComplete="new-password" name="moonstone-instructor-password" /></div><div className="mt-6 flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-center"><Button type="button" onClick={onSignIn} className="rounded-full px-6">Sign in</Button>{!instructorSignedIn && <Button type="button" onClick={onCreateAccount} variant="outline" className="rounded-full bg-white px-6">Create account</Button>}{instructorSignedIn && <Button type="button" onClick={onSignOut} variant="outline" className="rounded-full bg-white px-6">Sign out</Button>}</div><div className="mt-5 flex flex-wrap justify-center gap-2"><Badge label={isLoading ? "Loading" : isSaving ? "Saving" : "Ready"} tone={isLoading || isSaving ? "amber" : "green"} /><Badge label={instructorSignedIn ? instructorAccessApproved ? "Access approved" : "Access pending" : isConnected ? "Ready" : "Offline"} tone={instructorSignedIn && instructorAccessApproved ? "green" : instructorSignedIn ? "amber" : isConnected ? "blue" : "amber"} />{instructorSignedIn && <Badge label={instructorAccessChecked ? instructorAccessApproved ? "Instructor verified" : "Instructor not approved" : "Checking access"} tone={instructorAccessApproved ? "green" : "amber"} />}</div>{message && <div className="mt-5 rounded-2xl bg-stone-100 p-4 text-sm leading-6 text-stone-700">{message}</div>}</CardContent></Card></div>; }
function CalendarActionLink({ bookings, label = "Add to calendar", tone = "primary", className = "" }) { const calendarItems = normalizeCalendarBookings(bookings); const action = getCalendarAction(calendarItems); const calendarKey = calendarItems.map((booking) => `${booking.id || ""}-${booking.weekStart || ""}-${booking.day || ""}-${booking.time || ""}-${booking.sessionName || ""}-${booking.childOneName || ""}-${booking.childTwoName || ""}-${booking.totalPrice || ""}`).join("|"); const [downloadHref, setDownloadHref] = useState(""); useEffect(() => { if (!action?.download || typeof Blob === "undefined" || typeof URL === "undefined" || !URL.createObjectURL) { setDownloadHref(""); return; } const objectUrl = URL.createObjectURL(new Blob([buildCalendarFile(calendarItems)], { type: "text/calendar;charset=utf-8" })); setDownloadHref(objectUrl); return () => { if (URL.revokeObjectURL) URL.revokeObjectURL(objectUrl); }; }, [action?.download, calendarKey]); if (!action) return null; const styles = tone === "outline" ? "inline-flex items-center justify-center rounded-full border border-stone-200 bg-white px-4 py-2 text-sm font-medium text-stone-950 shadow-sm transition hover:bg-stone-100 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-stone-950 focus-visible:ring-offset-2" : "inline-flex items-center justify-center rounded-full bg-stone-950 px-4 py-2 text-sm font-medium text-white shadow-sm transition hover:bg-stone-800 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-stone-950 focus-visible:ring-offset-2"; return <a href={action.download && downloadHref ? downloadHref : action.href} target={action.target} rel={action.rel} download={action.download} className={classNames(styles, className)}>{label}</a>; }
function SuccessPage({ siteContent, updateContent, latestBookings, setActiveTab, editProps }) { const bookings = normalizeCalendarBookings(latestBookings); const successText = cleanCustomerSuccessText(siteContent.successText) || "Your lesson request has been received."; return <Card className="mx-auto max-w-2xl rounded-3xl text-center"><CardContent className="p-10"><div className="mx-auto flex h-16 w-16 items-center justify-center rounded-full bg-emerald-100"><CheckCircle2 className="h-9 w-9 text-emerald-700" /></div><EditableText value={siteContent.successTitle} onChange={(value) => updateContent("successTitle", value)} as="h3" className="mt-5 text-3xl font-semibold" {...editProps} /><EditableText value={successText} onChange={(value) => updateContent("successText", value)} as="p" multiline className="mt-3 text-stone-600" {...editProps} />{bookings.length > 0 && <div className="mt-6 grid gap-3 rounded-3xl border bg-white p-5 text-left text-sm"><p className="font-semibold">Booking summary</p>{bookings.map((booking) => <div key={booking.id} className="rounded-2xl bg-stone-50 p-4"><p><span className="font-semibold">Session:</span> {booking.sessionName}</p><p><span className="font-semibold">Child:</span> {booking.childOneName}{booking.childTwoName ? ` and ${booking.childTwoName}` : ""}</p><p><span className="font-semibold">Time:</span> {formatFullDate(getDateForDay(booking.weekStart, booking.day))} at {getBlockLabel(booking.time)}</p><p><span className="font-semibold">Price:</span> {currency(booking.totalPrice)} total{booking.sessionType === "duo" ? " · $40 per kid" : ""}</p></div>)}</div>}<div className="mt-6 flex flex-wrap justify-center gap-3">{bookings.length > 0 && <CalendarActionLink bookings={bookings} label="Add to calendar" />}<Button type="button" onClick={() => setActiveTab("book")} variant="outline" className="rounded-full">{siteContent.bookAnotherText}</Button></div></CardContent></Card>; }
function EditableText({ value, onChange, editMode, as = "span", className = "", multiline = false }) { if (editMode) { const fieldClass = classNames("w-full rounded-xl border-2 border-amber-300 bg-amber-50/95 px-2 py-1 text-stone-950 shadow-sm outline-none focus:border-amber-500 focus:bg-white", className); return multiline ? <textarea value={value} onChange={(event) => onChange(event.target.value)} rows={3} className={classNames(fieldClass, "min-h-[4rem] resize-y")} /> : <input value={value} onChange={(event) => onChange(event.target.value)} className={fieldClass} />; } const Tag = as; return <Tag className={className}>{value}</Tag>; }
function EditableListInline({ items, editMode, onChange, onAdd, onRemove }) { if (!editMode) return items.map((item, index) => <p key={index}>{item}</p>); return <div className="grid gap-3">{items.map((item, index) => <div key={index} className="flex gap-2"><EditableText value={item} onChange={(value) => onChange(index, value)} editMode as="span" className="flex-1 text-sm" /><Button type="button" size="sm" variant="outline" onClick={() => onRemove(index)} className="rounded-full bg-white text-stone-950">Remove</Button></div>)}<Button type="button" size="sm" variant="outline" onClick={onAdd} className="rounded-full bg-white text-stone-950">Add item</Button></div>; }
function EditablePillList({ items, editMode, onChange, onAdd, onRemove }) { if (!editMode) return <>{items.map((item, index) => <span key={index} className="rounded-full bg-white px-3 py-1.5 text-sm font-medium text-stone-800 ring-1 ring-pink-200">{item}</span>)}</>; return <div className="grid w-full gap-3 rounded-3xl bg-white p-4 ring-1 ring-pink-200">{items.map((item, index) => <div key={index} className="flex gap-2"><EditableText value={item} onChange={(value) => onChange(index, value)} editMode as="span" className="flex-1 text-sm" /><Button type="button" size="sm" variant="outline" onClick={() => onRemove(index)} className="rounded-full bg-white text-stone-950">Remove</Button></div>)}<Button type="button" size="sm" variant="outline" onClick={onAdd} className="rounded-full bg-white text-stone-950">Add activity</Button></div>; }
function EditableImage({ image, name, editMode, onImageChange, onFileChange, compact = false }) { function handleFile(file) { if (!file) return; if (onFileChange) { onFileChange(file); return; } const reader = new FileReader(); reader.onload = () => onImageChange(String(reader.result || "")); reader.readAsDataURL(file); } return <div className="relative">{image ? <img src={image} alt={name} className={classNames("w-full object-cover", compact ? "h-40 rounded-2xl" : "h-52")} /> : <div className={classNames("flex w-full flex-col items-center justify-center gap-3 bg-gradient-to-br from-stone-200 via-stone-100 to-amber-100 text-stone-700", compact ? "h-40 rounded-2xl" : "h-52")}><HorseIcon className="h-12 w-12" /><div className="text-center"><p className="font-semibold">{name || "Horse"}</p><p className="text-sm">Photo placeholder</p></div></div>}{editMode && <div className="absolute inset-x-3 bottom-3 flex flex-wrap items-center gap-2 rounded-2xl bg-white/95 p-3 shadow-lg ring-1 ring-amber-300"><label className="inline-flex cursor-pointer items-center gap-2 rounded-full bg-stone-950 px-4 py-2 text-sm font-medium text-white"><ImagePlus className="h-4 w-4" />Upload image<input type="file" accept="image/*" onChange={(event) => handleFile(event.target.files?.[0])} className="hidden" /></label><input value={image} onChange={(event) => onImageChange(event.target.value)} placeholder="Paste image URL" className="min-w-0 flex-1 rounded-full border border-stone-200 px-4 py-2 text-sm text-stone-950 outline-none focus:border-stone-950" /><Button type="button" size="sm" variant="outline" onClick={() => onImageChange("")} className="rounded-full">Clear</Button></div>}</div>; }
function FullSiteEditorCard({ siteContent, updateContent, devMode, disabled = false, startDevMode, stopDevMode }) { return <Card className="rounded-3xl border-amber-200 bg-amber-50/70"><CardContent className="p-7"><div className="flex flex-col gap-4 md:flex-row md:items-center md:justify-between"><div><div className="flex items-center gap-3">{devMode ? <Eye className="h-6 w-6" /> : <Pencil className="h-6 w-6" />}<EditableText value={siteContent.devModeTitle} onChange={(value) => updateContent("devModeTitle", value)} as="h3" className="text-2xl font-semibold" editMode={devMode} /></div><EditableText value={siteContent.devModeText} onChange={(value) => updateContent("devModeText", value)} as="p" multiline className="mt-2 text-stone-600" editMode={devMode} /></div>{devMode ? <Button type="button" onClick={stopDevMode} disabled={disabled} className="rounded-full bg-stone-950 text-white hover:bg-stone-800"><EditableText value={siteContent.exitDevModeButton} onChange={(value) => updateContent("exitDevModeButton", value)} as="span" editMode={devMode} /></Button> : <Button type="button" onClick={startDevMode} disabled={disabled} className="rounded-full bg-stone-950 text-white hover:bg-stone-800">{siteContent.enterDevModeButton}</Button>}</div><div className="mt-5 rounded-2xl bg-white p-4 text-sm text-stone-600">{disabled ? "Website editor mode is locked until an approved instructor signs in." : "When enabled, the instructor can use the top navigation to open every page, click directly into text blocks, edit them in place, upload horse images, paste image URLs, add/remove horse cards, and add/remove list items."}</div></CardContent></Card>; }
function WeekSelector({ weekOptions, value, onChange }) { return <label className="grid gap-2 text-sm font-medium text-stone-900">Week<select value={value} onChange={(event) => onChange(event.target.value)} className="rounded-2xl border border-stone-200 bg-white px-4 py-3 text-stone-950 outline-none focus:border-stone-950">{weekOptions.map((week) => <option key={week.startISO} value={week.startISO}>{week.label}</option>)}</select></label>; }
function BookingCard({ booking, onCancel, onDelete, onMarkPaid }) {
  const lessonDate = getDateForDay(booking.weekStart, booking.day);
  return <div className={classNames("rounded-3xl border bg-white p-4 sm:p-5", booking.status === "Canceled" && "opacity-60")}>
    <div className="grid gap-4 md:grid-cols-[minmax(0,1fr)_auto] md:items-start">
      <div className="min-w-0 [overflow-wrap:anywhere]">
        <div className="flex flex-wrap items-center gap-2">
          <h4 className="min-w-0 break-words text-lg font-semibold">{booking.childOneName}{booking.childTwoName ? ` + ${booking.childTwoName}` : ""}</h4>
          <Badge label={booking.sessionType === "duo" ? "Duo Session" : "Private Lesson"} tone={booking.sessionType === "duo" ? "purple" : "blue"} />
          <Badge label={booking.status} tone={booking.status === "Canceled" ? "gray" : "green"} />
          <Badge label={booking.paymentStatus} tone={booking.paymentStatus === "Paid" ? "green" : "amber"} />
        </div>
        <p className="mt-1 break-words text-sm text-stone-600">{booking.sessionName} · {formatFullDate(lessonDate)} at {getBlockLabel(booking.time)} · 75 minutes</p>
        <div className="mt-4 grid min-w-0 gap-2 text-sm text-stone-700 md:grid-cols-2">
          <p className="min-w-0"><span className="font-semibold">Parent:</span> {booking.parentName}</p>
          <p className="min-w-0"><span className="font-semibold">Kids:</span> {booking.kidCount}</p>
          <p className="min-w-0"><span className="font-semibold">Ages:</span> {booking.childOneAge}{booking.childTwoAge ? ` and ${booking.childTwoAge}` : ""}</p>
          <p className="min-w-0"><span className="font-semibold">Experience:</span> {booking.experience}</p>
          <p className="min-w-0"><span className="font-semibold">Email:</span> {booking.email}</p>
          <p className="min-w-0"><span className="font-semibold">Phone:</span> {booking.phone}</p>
          <p className="min-w-0"><span className="font-semibold">Emergency:</span> {booking.emergencyContactLabel || "Emergency contact"}: {booking.emergencyContact} · {booking.emergencyPhone}</p>
          {booking.secondParentName && <p className="min-w-0"><span className="font-semibold">Second parent:</span> {booking.secondParentName} · {booking.secondParentPhone}</p>}
          <p className="min-w-0"><span className="font-semibold">Price:</span> {currency(booking.totalPrice)} total · {currency(booking.pricePerKid)} per kid</p>
        </div>
        {booking.goals && <p className="mt-3 break-words text-sm text-stone-700"><span className="font-semibold">Goals:</span> {booking.goals}</p>}
        {booking.medicalNotes && <p className="mt-2 break-words text-sm text-stone-700"><span className="font-semibold">Medical:</span> {booking.medicalNotes}</p>}
      </div>
      <div className="flex shrink-0 flex-wrap gap-2 md:max-w-[13rem] md:justify-end">
        <CalendarActionLink bookings={booking} label="Calendar" tone="outline" className="h-9 px-3" />
        {booking.paymentStatus !== "Paid" && booking.status !== "Canceled" && <Button type="button" size="sm" onClick={() => onMarkPaid(booking.id)} className="rounded-full">Mark paid</Button>}
        {booking.status !== "Canceled" && <Button type="button" variant="outline" size="sm" onClick={() => onCancel(booking.id)} className="rounded-full">Cancel</Button>}
        <Button type="button" variant="outline" size="sm" onClick={() => onDelete(booking.id)} className="rounded-full border-red-200 bg-white text-red-700 hover:bg-red-50">Delete forever</Button>
      </div>
    </div>
  </div>;
}
function Badge({ label, tone }) { const styles = { green: "bg-emerald-100 text-emerald-700", amber: "bg-amber-100 text-amber-800", gray: "bg-stone-200 text-stone-700", blue: "bg-blue-100 text-blue-700", purple: "bg-purple-100 text-purple-700" }; return <span className={classNames("rounded-full px-3 py-1 text-xs font-medium", styles[tone] || styles.gray)}>{label}</span>; }
function StatCard({ label, value }) { return <Card className="rounded-3xl"><CardContent className="p-5"><p className="text-sm text-stone-500">{label}</p><p className="mt-2 text-3xl font-semibold">{value}</p></CardContent></Card>; }
function HorseIcon({ className = "" }) { return <svg className={className} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true"><path d="M5 19v-6.5L3.5 11l1.25-3.5L8 5l4.5 1 3.25 3.25 3.75.75 1 2.5-2 2.5H16l-2 4" /><path d="M8 19v-5" /><path d="M12 19v-4" /><path d="M8 5 7 2" /><path d="M10.5 5 11 2.5" /><path d="M17 10.5h.01" /></svg>; }
function FeatureCard({ icon, title, text, editMode = false, onTitleChange, onTextChange }) { return <Card className="rounded-3xl"><CardContent className="p-7"><div className="mb-5 flex h-12 w-12 items-center justify-center rounded-2xl bg-stone-950 text-white">{React.isValidElement(icon) ? React.cloneElement(icon, { className: "h-6 w-6" }) : null}</div><EditableText value={title} onChange={onTitleChange || (() => {})} as="h3" className="text-xl font-semibold" editMode={editMode} /><EditableText value={text} onChange={onTextChange || (() => {})} as="p" multiline className="mt-3 leading-7 text-stone-600" editMode={editMode} /></CardContent></Card>; }
function strokeToPath(stroke) { return stroke.map((point, index) => `${index === 0 ? "M" : "L"}${Number(point.x || 0).toFixed(1)} ${Number(point.y || 0).toFixed(1)}`).join(" "); }
function SignaturePad({ value, onChange, required = false }) {
  const svgRef = useRef(null);
  const drawingRef = useRef(false);
  const activePointerIdRef = useRef(null);
  const previousScrollStylesRef = useRef(null);
  const [strokes, setStrokes] = useState(() => parseSignature(value));

  useEffect(() => { if (!value) setStrokes([]); }, [value]);
  useEffect(() => () => unlockPageScroll(), []);

  function lockPageScroll() {
    if (typeof document === "undefined" || previousScrollStylesRef.current) return;
    previousScrollStylesRef.current = {
      bodyOverflow: document.body.style.overflow,
      htmlOverscroll: document.documentElement.style.overscrollBehavior,
    };
    document.body.style.overflow = "hidden";
    document.documentElement.style.overscrollBehavior = "none";
  }

  function unlockPageScroll() {
    if (typeof document === "undefined" || !previousScrollStylesRef.current) return;
    document.body.style.overflow = previousScrollStylesRef.current.bodyOverflow;
    document.documentElement.style.overscrollBehavior = previousScrollStylesRef.current.htmlOverscroll;
    previousScrollStylesRef.current = null;
  }

  function getPoint(event) {
    const rect = svgRef.current?.getBoundingClientRect();
    if (!rect) return { x: 0, y: 0 };
    return { x: ((event.clientX - rect.left) / rect.width) * 600, y: ((event.clientY - rect.top) / rect.height) * 180 };
  }

  function updateStrokes(next) {
    setStrokes(next);
    onChange(JSON.stringify(next));
  }

  function startDrawing(event) {
    event.preventDefault();
    event.stopPropagation();
    lockPageScroll();
    drawingRef.current = true;
    activePointerIdRef.current = event.pointerId;
    event.currentTarget.setPointerCapture?.(event.pointerId);
    updateStrokes([...strokes, [getPoint(event)]]);
  }

  function draw(event) {
    if (!drawingRef.current || activePointerIdRef.current !== event.pointerId) return;
    event.preventDefault();
    event.stopPropagation();
    const point = getPoint(event);
    setStrokes((prev) => {
      const next = prev.map((stroke, index) => index === prev.length - 1 ? [...stroke, point] : stroke);
      onChange(JSON.stringify(next));
      return next;
    });
  }

  function stopDrawing(event) {
    if (activePointerIdRef.current !== null && event?.pointerId !== undefined && activePointerIdRef.current !== event.pointerId) return;
    drawingRef.current = false;
    activePointerIdRef.current = null;
    event?.currentTarget?.releasePointerCapture?.(event.pointerId);
    unlockPageScroll();
  }

  return <div className="grid touch-none select-none gap-2 text-sm font-medium md:col-span-2" style={{ touchAction: "none", WebkitUserSelect: "none", userSelect: "none" }}><div className="flex items-center justify-between gap-3"><span>Draw parent/guardian signature{required && <RequiredMark />}</span><Button type="button" variant="outline" size="sm" onClick={() => { setStrokes([]); onChange(""); }} className="rounded-full">Clear</Button></div><div className="rounded-2xl border border-stone-200 bg-white p-3"><svg ref={svgRef} viewBox="0 0 600 180" className="h-36 w-full touch-none select-none rounded-xl bg-stone-50 sm:h-40" style={{ touchAction: "none", WebkitUserSelect: "none", userSelect: "none" }} onPointerDown={startDrawing} onPointerMove={draw} onPointerUp={stopDrawing} onPointerCancel={stopDrawing} onLostPointerCapture={stopDrawing}><line x1="30" y1="135" x2="570" y2="135" stroke="currentColor" strokeWidth="1" className="text-stone-300" />{strokes.map((stroke, index) => <path key={index} d={strokeToPath(stroke)} fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round" className="text-stone-950" />)}</svg></div><p className="text-xs text-stone-500">Sign with a finger, trackpad, mouse, or stylus.</p></div>;
}
function EmergencyContactSection({ form, setForm, sessionType }) { const contact = getEmergencyContactFromForm(form, sessionType); const options = [{ value: "primary", label: "Same as primary parent/guardian" }, ...(sessionType === "duo" ? [{ value: "second", label: "Use second parent/guardian" }] : []), { value: "other", label: "Use a different emergency contact" }]; return <div className="grid gap-4 rounded-3xl border bg-white p-4 md:col-span-2"><div><p className="text-sm font-semibold">Emergency contact<RequiredMark /></p><p className="mt-1 text-sm text-stone-600">Choose whether the emergency contact is already listed above or someone different.</p></div><div className="flex flex-wrap gap-2">{options.map((option) => <Button key={option.value} type="button" variant={form.emergencyContactType === option.value ? "default" : "outline"} onClick={() => setForm((prev) => ({ ...prev, emergencyContactType: option.value }))} className="rounded-full">{option.label}</Button>)}</div>{form.emergencyContactType === "other" ? <div className="grid gap-4 md:grid-cols-2"><Input label="Emergency contact name" required value={form.emergencyContact} onChange={(value) => setForm((prev) => ({ ...prev, emergencyContact: value }))} /><Input label="Emergency contact phone" type="tel" required value={form.emergencyPhone} onChange={(value) => setForm((prev) => ({ ...prev, emergencyPhone: value }))} /></div> : <div className="rounded-2xl bg-stone-100 p-4 text-sm text-stone-700"><span className="font-semibold">Selected:</span> {contact.label}{contact.name || contact.phone ? ` — ${contact.name || "missing name"} · ${contact.phone || "missing phone"}` : " — fill out the matching parent fields above"}</div>}</div>; }
function RequiredMark() { return <span className="ml-1 text-red-600">*</span>; }
function Input({ label, value, onChange, required = false, type = "text", autoComplete, name }) { return <label className="grid gap-2 text-sm font-medium"><span>{label}{required && <RequiredMark />}</span><input type={type} value={value} required={required} aria-required={required} autoComplete={autoComplete} name={name} onChange={(event) => onChange(event.target.value)} className="rounded-2xl border border-stone-200 bg-white px-4 py-3 outline-none focus:border-stone-950" /></label>; }
function Textarea({ label, value, onChange, required = false }) { return <label className="grid gap-2 text-sm font-medium md:col-span-2"><span>{label}{required && <RequiredMark />}</span><textarea value={value} required={required} aria-required={required} onChange={(event) => onChange(event.target.value)} rows={3} className="resize-none rounded-2xl border border-stone-200 bg-white px-4 py-3 outline-none focus:border-stone-950" /></label>; }
function Select({ label, value, onChange, options, required = false }) { return <label className="grid gap-2 text-sm font-medium"><span>{label}{required && <RequiredMark />}</span><select value={value} required={required} aria-required={required} onChange={(event) => onChange(event.target.value)} className="rounded-2xl border border-stone-200 bg-white px-4 py-3 outline-none focus:border-stone-950"><option value="">Select one</option>{options.map((option) => <option key={option} value={option}>{option}</option>)}</select></label>; }
function Checkbox({ label, checked, onChange, required = false }) { return <label className="flex items-start gap-3 text-sm leading-6"><input type="checkbox" checked={checked} required={required} aria-required={required} onChange={(event) => onChange(event.target.checked)} className="mt-1 h-4 w-4 rounded border-stone-300" /><span>{label}{required && <RequiredMark />}</span></label>; }
